  pull(rate)

Log transformation

The codeThe graph



It might be more informative to see how many countries have average daily incomes of about $1 (extremely poor), $2 (very poor), $4 (poor), $8 (middle), $16 (well off), $32 (rich), $64 (very rich) per day.
if we apply a log base 2 transform:


gapminder |&gt;  
  filter(year == past_year & !is.na(gdp)) |&gt; 
  ggplot(aes(log2(dollars_per_day))) +  
  geom_histogram(binwidth = 1, color = "black")

Comparing distributions

The codeThe graph



We reorder the regions by the median value and use a log scale.


gapminder |&gt;  
  filter(year == past_year & !is.na(gdp)) |&gt; 
  mutate(region = reorder(region, dollars_per_day, FUN = median)) |&gt; 
  ggplot(aes(dollars_per_day, region)) + 
  geom_point() + 
  scale_x_continuous(trans = "log2")

Ridge plots

The codeThe plot



Here is the income data shown above with boxplots but with a ridge plot.


library(ggridges) 
p &lt;- gapminder |&gt;  
  filter(year == past_year & !is.na(dollars_per_day)) |&gt; 
  mutate(group = reorder(group, dollars_per_day, FUN = median)) |&gt; 
  ggplot(aes(dollars_per_day, group)) +  
  scale_x_continuous(trans = "log2")  
p  + geom_density_ridges()

Case study 1
We keep countries that exist both in 1970 and 2010:

past_year &lt;- 1970 
present_year &lt;- 2010 
years &lt;- c(past_year, present_year) 
country_list &lt;- gapminder |&gt;  
  filter(year %in% c(present_year, past_year)) |&gt; 
  group_by(country) |&gt; 
  summarize(n = sum(!is.na(dollars_per_day)), .groups = "drop") |&gt;  #n can be 0, 1, 2
  # .groups = "drop": removing grouping, returning a ungrouped tibble
  filter(n == 2) |&gt; 
  pull(country) # extract the country column as a plain char vector

Case study 1: Compare districtuion

The codeThe graph



gapminder |&gt;  
  filter(year %in% years & country %in% country_list) |&gt; 
  mutate(west = ifelse(group == "West", "West", "Developing")) |&gt; 
  ggplot(aes(dollars_per_day)) + 
  geom_histogram(binwidth = 1, color = "black") + 
  scale_x_continuous(trans = "log2") +  
  facet_grid(year ~ west)

Accessing computed variables

The codeThe graph


Use after_stat to access density.

p &lt;- gapminder |&gt;  
  filter(year %in% years & country %in% country_list) |&gt; 
  mutate(group = ifelse(group == "West", "West", "Developing")) |&gt; 
  ggplot(aes(dollars_per_day, y = after_stat(count), fill = group)) + 
  scale_x_continuous(trans = "log2", limits = c(0.125, 300)) 
p + geom_density(alpha = 0.2) + facet_grid(year ~ .)

Multiple ridge plot

The codeThe graph


To visualize if any of the groups defined above are driving this we can quickly make a ridge plot:

gapminder |&gt;  
  filter(year %in% years & !is.na(dollars_per_day)) |&gt; 
  mutate(group = reorder(group, dollars_per_day, FUN = median)) |&gt;
  ggplot(aes(dollars_per_day, group)) +  
  scale_x_continuous(trans = "log2") +  
  geom_density_ridges(bandwidth = 1.5) + # bandwidth: set KDE bandwidth
  facet_grid(. ~ year)

Stacking densities

The graphThe code










Another way to achieve this is by stacking the densities on top of each other:


gapminder |&gt;  
    filter(year %in% years & country %in% country_list) |&gt; 
  group_by(year) |&gt; 
  mutate(weight = population/sum(population)*2) |&gt; 
  ungroup() |&gt; # remove grouping by year
  ggplot(aes(dollars_per_day, fill = group)) + # no y-aes
  scale_x_continuous(trans = "log2", limits = c(0.125, 300)) +  
  geom_density(alpha = 0.2, bw = 0.75, position = "stack") +  
  facet_grid(year ~ .)

Weighted densities

The graphThe code









Here we weigh the countries by size:

gapminder |&gt;  
  filter(year %in% years & country %in% country_list) |&gt; 
  group_by(year) |&gt; 
  mutate(weight = population/sum(population)*2) |&gt; 
  ungroup() |&gt; 
  ggplot(aes(dollars_per_day, fill = group, weight = weight)) + 
  scale_x_continuous(trans = "log2", limits = c(0.125, 300)) +  
  geom_density(alpha = 0.2, bw = 0.75, position = "stack") + 
  facet_grid(year ~ .)

Case study 2

the_disease &lt;- "Measles" 
dat &lt;- us_contagious_diseases |&gt; 
  filter(!state %in% c("Hawaii","Alaska") & disease == the_disease) |&gt; 
  mutate(rate = count / population * 10000 * 52 / weeks_reporting) |&gt;  
  mutate(state = reorder(state, ifelse(year &lt;= 1963, rate, NA),  
                         median, na.rm = TRUE))

